import{_ as t,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"压缩恢复: 技能自动恢复 | opencode-agent-skills","description":"学习 opencode-agent-skills 的压缩恢复机制。在会话压缩后自动恢复技能列表，使用 synthetic 消息保持技能可用。","frontmatter":{"title":"压缩恢复: 技能自动恢复 | opencode-agent-skills","sidebarTitle":"压缩后技能不丢","subtitle":"压缩恢复: 技能自动恢复","description":"学习 opencode-agent-skills 的压缩恢复机制。在会话压缩后自动恢复技能列表，使用 synthetic 消息保持技能可用。","tags":["上下文管理","会话持久","高级功能"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),l={name:"zh/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function n(o,a,r,d,p,h){return s(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="上下文压缩恢复机制" tabindex="-1">上下文压缩恢复机制 <a class="header-anchor" href="#上下文压缩恢复机制" aria-label="Permalink to &quot;上下文压缩恢复机制&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解插件如何在会话压缩后保持技能可用</li><li>知道压缩恢复的触发时机和执行流程</li><li>能够验证压缩恢复是否正常工作</li><li>理解 synthetic 消息在恢复机制中的作用</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>在长会话中，OpenCode 会执行<strong>上下文压缩</strong>（Context Compaction）以节省 Token。压缩后的会话只保留最近的消息，早期历史记录（包括之前注入的技能内容）会被移除。</p><p>这导致一个问题：如果技能内容被压缩掉了，AI 就不再知道有哪些技能可用，也无法使用已加载的技能。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>压缩恢复机制是<strong>自动运行</strong>的，你无需手动干预。但了解它的原理后，你可以在以下场景排查问题：</p><ul><li>长会话中 AI 突然&quot;忘记&quot;了技能</li><li>需要调试技能在压缩后的可用性</li><li>想理解插件的会话管理策略</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什么是上下文压缩" tabindex="-1">什么是上下文压缩？ <a class="header-anchor" href="#什么是上下文压缩" aria-label="Permalink to &quot;什么是上下文压缩？&quot;">​</a></h3><p>OpenCode 会话随着消息增多会越来越长，当 Token 使用量接近上限时，系统会自动执行<strong>上下文压缩</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[会话初始] → [消息 1] → [消息 2] → ... → [消息 50]</span></span>
<span class="line"><span>                          ↑ 压缩点：只保留最近 10 条消息</span></span></code></pre></div><p>压缩后，早期消息（包括技能注入内容）会被移除，AI 只能看到最近的消息历史。</p><h3 id="压缩恢复机制的工作原理" tabindex="-1">压缩恢复机制的工作原理 <a class="header-anchor" href="#压缩恢复机制的工作原理" aria-label="Permalink to &quot;压缩恢复机制的工作原理&quot;">​</a></h3><p>插件监听 <code>session.compacted</code> 事件，一旦检测到压缩发生，立即执行以下恢复操作：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[会话压缩触发] --&gt; B[session.compacted 事件]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{已启用 Superpowers?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| D[重新注入 Superpowers 提示]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否| E[跳过 Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[重新注入技能列表]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[清空已加载技能记录]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[恢复完成]</span></span></code></pre></div><p><strong>关键点</strong>：</p><ul><li>恢复是<strong>自动的</strong>，无需手动触发</li><li>恢复后的技能列表包含<strong>所有发现的技能</strong>（不仅仅是之前加载的）</li><li>已加载技能的记录会被清空，允许 AI 重新评估需要哪些技能</li></ul><h3 id="synthetic-消息的作用" tabindex="-1">Synthetic 消息的作用 <a class="header-anchor" href="#synthetic-消息的作用" aria-label="Permalink to &quot;Synthetic 消息的作用&quot;">​</a></h3><p>插件使用 <strong>Synthetic Message Injection</strong> 机制注入内容：</p><table tabindex="0"><thead><tr><th>属性</th><th>值</th><th>含义</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>AI 不会对注入内容本身进行回复</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>标记为系统生成内容，不计入用户输入，不在 UI 显示</td></tr></tbody></table><p>这意味着压缩恢复注入的内容：</p><ul><li>对用户完全透明（看不到）</li><li>不消耗用户消息配额</li><li>但会被 AI 读取并理解</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p>本教程需要：</p><ul><li>已安装 OpenCode Agent Skills 插件</li><li>理解技能加载的基础知识</li><li>一个长会话用于测试压缩效果</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>无需额外准备，压缩恢复机制是插件内置功能。</p></div><h2 id="跟我做-验证压缩恢复效果" tabindex="-1">跟我做：验证压缩恢复效果 <a class="header-anchor" href="#跟我做-验证压缩恢复效果" aria-label="Permalink to &quot;跟我做：验证压缩恢复效果&quot;">​</a></h2><h3 id="第-1-步-启动新会话" tabindex="-1">第 1 步：启动新会话 <a class="header-anchor" href="#第-1-步-启动新会话" aria-label="Permalink to &quot;第 1 步：启动新会话&quot;">​</a></h3><p><strong>为什么</strong> 验证会话初始化时技能列表是否正常注入</p><p>启动一个新会话，输入任何消息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你好</span></span></code></pre></div><p><strong>你应该看到</strong>：AI 正常回复，并在后台自动注入了技能列表（对用户不可见）</p><h3 id="第-2-步-加载一个技能" tabindex="-1">第 2 步：加载一个技能 <a class="header-anchor" href="#第-2-步-加载一个技能" aria-label="Permalink to &quot;第 2 步：加载一个技能&quot;">​</a></h3><p><strong>为什么</strong> 确保技能内容被注入到上下文</p><p>调用 <code>use_skill</code> 工具：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 get_available_skills 查看可用技能，然后用 use_skill 加载其中一个技能</span></span></code></pre></div><p><strong>你应该看到</strong>：AI 列出可用技能，然后加载你选择的技能</p><h3 id="第-3-步-触发上下文压缩" tabindex="-1">第 3 步：触发上下文压缩 <a class="header-anchor" href="#第-3-步-触发上下文压缩" aria-label="Permalink to &quot;第 3 步：触发上下文压缩&quot;">​</a></h3><p><strong>为什么</strong> 模拟长会话场景，触发 OpenCode 的压缩机制</p><p>持续发送消息，模拟长对话：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>消息 1：测试内容</span></span>
<span class="line"><span>消息 2：继续测试</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（重复发送 20-30 条消息）</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>随着消息增多，会话历史变长</li><li>达到一定长度后，OpenCode 自动执行压缩</li><li>压缩后，早期消息（包括技能注入）被移除</li></ul><h3 id="第-4-步-检查恢复效果" tabindex="-1">第 4 步：检查恢复效果 <a class="header-anchor" href="#第-4-步-检查恢复效果" aria-label="Permalink to &quot;第 4 步：检查恢复效果&quot;">​</a></h3><p><strong>为什么</strong> 验证压缩后技能列表是否被重新注入</p><p>压缩后，再次让 AI 使用技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我使用 git-helper 技能创建新分支（假设你已安装 git-helper 技能）</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>AI 仍然知道有哪些技能可用（证明技能列表已恢复）</li><li>AI 能够正常加载和使用技能（证明技能功能未受压缩影响）</li></ul><h3 id="第-5-步-验证-synthetic-消息注入" tabindex="-1">第 5 步：验证 Synthetic 消息注入 <a class="header-anchor" href="#第-5-步-验证-synthetic-消息注入" aria-label="Permalink to &quot;第 5 步：验证 Synthetic 消息注入&quot;">​</a></h3><p><strong>为什么</strong> 确认恢复机制使用的是 synthetic 消息，不会干扰对话</p><p>如果插件支持，可以检查会话消息历史（取决于 OpenCode 功能）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用调试工具查看会话消息历史</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>恢复的技能列表消息标记为 <code>synthetic: true</code></li><li>这些消息不会显示在正常对话界面</li></ul><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成上述步骤后，你应该能够确认：</p><ul><li>[ ] 长会话中 AI 仍能访问技能列表</li><li>[ ] 压缩后技能加载功能正常工作</li><li>[ ] 恢复过程对用户完全透明</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="问题-1-压缩后-ai-说-找不到技能" tabindex="-1">问题 1：压缩后 AI 说&quot;找不到技能&quot; <a class="header-anchor" href="#问题-1-压缩后-ai-说-找不到技能" aria-label="Permalink to &quot;问题 1：压缩后 AI 说&quot;找不到技能&quot;&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>插件未正确监听 <code>session.compacted</code> 事件</li><li>技能目录路径发生变化</li></ul><p><strong>解决方法</strong>：</p><ol><li><p><strong>验证压缩事件是否触发</strong></p><ul><li>通过「跟我做」中的第 3 步和第 4 步，确认压缩后 AI 仍能访问技能列表</li><li>如果 AI 能正常使用技能，说明压缩恢复机制工作正常</li></ul></li><li><p><strong>检查插件是否正确加载</strong></p><ul><li>重启 OpenCode</li><li>启动新会话后，让 AI 列出可用技能（<code>get_available_skills</code>）</li><li>如果能看到技能列表，说明插件已正确加载</li></ul></li></ol><h3 id="问题-2-恢复的技能列表为空" tabindex="-1">问题 2：恢复的技能列表为空 <a class="header-anchor" href="#问题-2-恢复的技能列表为空" aria-label="Permalink to &quot;问题 2：恢复的技能列表为空&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>技能发现路径中没有技能</li><li>技能文件格式错误</li></ul><p><strong>解决方法</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动查询可用技能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">使用</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 查看技能列表</span></span></code></pre></div><p>如果返回空列表，检查技能目录和文件格式。</p><h3 id="问题-3-压缩后已加载技能状态丢失" tabindex="-1">问题 3：压缩后已加载技能状态丢失 <a class="header-anchor" href="#问题-3-压缩后已加载技能状态丢失" aria-label="Permalink to &quot;问题 3：压缩后已加载技能状态丢失&quot;">​</a></h3><p><strong>这是预期行为</strong>，不是 Bug。恢复机制会清空 <code>loadedSkillsPerSession</code> 记录，允许 AI 重新评估需要哪些技能。</p><p><strong>解决方法</strong>：AI 会根据上下文自动决定是否重新加载技能，无需手动干预。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>压缩恢复机制通过以下方式确保技能在长会话中的可用性：</p><ol><li><strong>监听压缩事件</strong>：自动检测 <code>session.compacted</code> 事件</li><li><strong>重新注入技能列表</strong>：使用 <code>&lt;available-skills&gt;</code> 标签注入所有技能</li><li><strong>可选 Superpowers 恢复</strong>：如果启用，同时恢复 Superpowers 提示</li><li><strong>使用 Synthetic 消息</strong>：恢复过程对用户透明，不影响对话</li><li><strong>重置已加载记录</strong>：清空已加载技能集合，允许重新评估</li></ol><p>这套机制确保了：</p><ul><li>长会话中技能始终可用</li><li>恢复过程自动化且无感知</li><li>AI 可以根据最新上下文决定使用哪些技能</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../faq/troubleshooting/">常见问题排查</a></strong>。</p><p>你会学到：</p><ul><li>常见错误和异常的处理方法</li><li>压缩恢复相关的排查技巧</li><li>其他使用问题的解决方案</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>压缩事件监听</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>首次消息初始化</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>技能列表注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Synthetic 消息注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>会话状态管理</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>关键变量</strong>：</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>：记录已完成初始化的会话 ID</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>：记录每个会话已加载的技能名称</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>injectSkillsList()</code>：注入可用技能列表到会话</li><li><code>injectSyntheticContent()</code>：使用 synthetic 消息注入内容</li><li><code>getSessionContext()</code>：获取会话的 model 和 agent 信息</li></ul></details>`,85)])])}const u=t(l,[["render",n]]);export{g as __pageData,u as default};
